const cp = require('child_process');
const url = ($json.body && $json.body.url) || '';
if (!url) return [{ json: { output: '❌ Falta el parámetro url' } }];

try {
  // Escape docker container to host GUI using nsenter via mounted docker socket
  const cmd = `docker run --rm --pid=host --privileged alpine nsenter -t 1 -m -u -n -i su - lucy-ubuntu -c "export DISPLAY=:0; xdg-open '${url}'"`;
  cp.execSync(cmd, { timeout: 15000 });
  return [{ json: { output: '▶️ Abriendo video en el host: ' + url } }];
} catch(e) {
  return [{ json: { output: '❌ Error al abrir video: ' + e.message } }];
}
